1	//! Round-13 REGENERATION tests for the edge layer (BEHAVIOR.md Â§3c, Â§6).
2	//!
3	//! Unlike the opaque round-trip (which preserves parsed edge attributes and
4	//! port strings verbatim), these tests rebuild each graph's edge set from a
5	//! STRUCTURED [`System`] â€” every edge is a typed [`SysEdge`] carrying an
6	//! [`EndRef`] endpoint reference and an [`EdgeStyle`] â€” and assert that
7	//! [`generate`] re-emits the payload's edge section byte-for-byte. This
8	//! exercises the full (color, style) vocabulary and the record info-port anchor
9	//! ([`EndRef::Info`]) through the real id/port allocator.
10	
11	use graph_clean::dot::to_dot;
12	use graph_clean::generate::*;
13	use graph_clean::model::*;
14	use std::collections::{BTreeSet, HashMap};
15	
16	#[path = "parse_util.rs"]
17	mod parse_util;
18	use parse_util::parse;
19	
20	/// The complete observed edge-style vocabulary and the exact attribute bracket
21	/// each renders (Â§3c census over the whole 12 022-file corpus: these eleven
22	/// (color, style) attribute sets are the entire observed set, with counts
23	/// red/dashed 147937, bold 86531, bold+gray50 86298, gray30 50359,
24	/// blue3/dashed 37726, orangered2 29917, invis 25271, black/dashed 6909,
25	/// purple/dashed 2416, dotted/green 2394, darkorange3/dashed 1553).
26	const STYLE_VOCAB: &[(EdgeStyle, &str)] = &[
27	    (EdgeStyle::StructuralGray, "[style=\"bold\",weight=\"10.0\",color=\"gray50\"]"),
28	    (EdgeStyle::Structural, "[style=\"bold\",weight=\"10.0\"]"),
29	    (EdgeStyle::Message, "[color=\"gray30\"]"),
30	    (EdgeStyle::KnowledgeDeduction, "[color=\"red\",style=\"dashed\"]"),
31	    (EdgeStyle::Deduction, "[color=\"orangered2\"]"),
32	    (EdgeStyle::TemporalBlue, "[color=\"blue3\",style=\"dashed\"]"),
33	    (EdgeStyle::TemporalBlack, "[color=\"black\",style=\"dashed\"]"),
34	    // The three round-13 additions:
35	    (EdgeStyle::PurpleDashed, "[color=\"purple\",style=\"dashed\"]"),
36	    (EdgeStyle::GreenDotted, "[style=\"dotted\",color=\"green\"]"),
37	    (EdgeStyle::DarkorangeDashed, "[color=\"darkorange3\",style=\"dashed\"]"),
38	    (EdgeStyle::Invis, "[style=\"invis\"]"),
39	];
40	
41	/// Every style in the vocabulary renders to its exact captured attribute bracket
42	/// (note `dotted`/`green` is the sole `style`-before-`color` ordering).
43	#[test]
44	fn edge_style_vocabulary_renders_byte_exact() {
45	    for (style, bracket) in STYLE_VOCAB {
46	        let sys = System {
47	            nodes: vec![
48	                GraphNode::Temporal { var: "a".into() },
49	                GraphNode::Temporal { var: "b".into() },
50	            ],
51	            edges: vec![SysEdge::new(EndRef::Whole(0), EndRef::Whole(1), *style)],
52	            ..System::default()
53	        };
54	        let dot = to_dot(&generate(&sys));
55	        let want = format!("n0 -> n1{};", bracket);
56	        assert!(dot.contains(&want), "style {:?} must render `{}`; got:\n{}", style, want, dot);
57	    }
58	}
