60	/// The vocabulary is exactly the observed set: every distinct edge bracket in
61	/// the committed regeneration corpus is one of the eleven, and all eleven occur.
62	#[test]
63	fn fixture_corpus_uses_only_the_known_vocabulary() {
64	    let known: BTreeSet<&str> = STYLE_VOCAB.iter().map(|(_, b)| *b).collect();
65	    let mut seen: BTreeSet<String> = BTreeSet::new();
66	    for (_, dot) in regen_fixtures() {
