81	// ---------------------------------------------------------------------------
82	// Regeneration: rebuild each capture's edge section from a structured System.
83	// ---------------------------------------------------------------------------
84	
85	/// A parsed node's id footprint, enough to reproduce its id/port allocation.
86	enum Foot {
87	    Record { nprem: usize, nconcl: usize },
88	    Single,
89	}
90	
91	/// The role of a record port, i.e. which [`EndRef`] addresses it.
92	#[derive(Clone, Copy)]
93	enum PortRole {
94	    Prem(usize),
95	    Info,
96	    Concl(usize),
97	}
98	
99	/// One parsed node with its integer id and, for records, its per-role ports.
100	struct NodeInfo {
101	    node_id: usize,
102	    foot: Foot,
103	    prem_ports: Vec<usize>,
104	    info_port: Option<usize>,
105	    concl_ports: Vec<usize>,
106	}
107	
108	fn nid(s: &str) -> usize {
109	    s.trim_start_matches('n').parse().unwrap_or_else(|_| panic!("bad id {s}"))
110	}
111	
112	fn node_info(n: &Node) -> NodeInfo {
113	    let node_id = nid(&n.id);
114	    match &n.kind {
115	        NodeKind::Record(r) => {
116	            // The info cell is the record's single middle-group cell; its text is
117	            // the only one that begins with a temporal `#` sigil (facts never do).
118	            let info_col = r
119	                .columns
120	                .iter()
121	                .position(|col| col.first().is_some_and(|c| c.text.starts_with('#')))
122	                .expect("record must have an info cell");
123	            let mut prem_ports = Vec::new();
124	            let mut concl_ports = Vec::new();
125	            let mut info_port = None;
126	            for (ci, col) in r.columns.iter().enumerate() {
127	                if ci < info_col {
128	                    prem_ports.extend(col.iter().map(|c| nid(&c.port)));
129	                } else if ci == info_col {
130	                    info_port = Some(nid(&col[0].port));
131	                } else {
132	                    concl_ports.extend(col.iter().map(|c| nid(&c.port)));
133	                }
134	            }
135	            let foot = Foot::Record { nprem: prem_ports.len(), nconcl: concl_ports.len() };
136	            NodeInfo { node_id, foot, prem_ports, info_port, concl_ports }
137	        }
138	        // Ellipse / shaped / plain (legend) each occupy a single id.
139	        _ => NodeInfo { node_id, foot: Foot::Single, prem_ports: Vec::new(), info_port: None, concl_ports: Vec::new() },
140	    }
141	}
142	
143	fn collect(stmts: &[Stmt], nodes: &mut Vec<NodeInfo>, edges: &mut Vec<Edge>) {
144	    for s in stmts {
145	        match s {
146	            Stmt::Node(n) => nodes.push(node_info(n)),
147	            Stmt::Edge(e) => edges.push(e.clone()),
148	            Stmt::Cluster(c) => collect(&c.body, nodes, edges),
149	            Stmt::RankBlock(b) => collect(&b.body, nodes, edges),
150	        }
151	    }
152	}
153	
154	fn map_style(attrs: &[(String, String)]) -> EdgeStyle {
155	    let a: Vec<(&str, &str)> = attrs.iter().map(|(k, v)| (k.as_str(), v.as_str())).collect();
156	    match a.as_slice() {
157	        [("style", "bold"), ("weight", "10.0"), ("color", "gray50")] => EdgeStyle::StructuralGray,
158	        [("style", "bold"), ("weight", "10.0")] => EdgeStyle::Structural,
159	        [("color", "gray30")] => EdgeStyle::Message,
160	        [("color", "red"), ("style", "dashed")] => EdgeStyle::KnowledgeDeduction,
161	        [("color", "orangered2")] => EdgeStyle::Deduction,
162	        [("color", "blue3"), ("style", "dashed")] => EdgeStyle::TemporalBlue,
163	        [("color", "black"), ("style", "dashed")] => EdgeStyle::TemporalBlack,
164	        [("color", "purple"), ("style", "dashed")] => EdgeStyle::PurpleDashed,
165	        [("style", "dotted"), ("color", "green")] => EdgeStyle::GreenDotted,
166	        [("color", "darkorange3"), ("style", "dashed")] => EdgeStyle::DarkorangeDashed,
167	        [("style", "invis")] => EdgeStyle::Invis,
168	        _ => panic!("un-modeled edge style {attrs:?}"),
169	    }
170	}
171	
172	/// Result of rebuilding one capture: the reconstructed and captured edge-line
173	/// sections, plus coverage flags for the acceptance assertions.
174	struct Rebuilt {
175	    got: Vec<String>,
176	    want: Vec<String>,
177	    used_info: bool,
178	    styles: BTreeSet<String>,
179	}
180	
181	fn rebuild(dot: &str) -> Rebuilt {
182	    let g = parse(dot);
183	    let mut nodes: Vec<NodeInfo> = Vec::new();
184	    let mut edges: Vec<Edge> = Vec::new();
185	    collect(&g.body, &mut nodes, &mut edges);
186	
187	    // Allocation order == ascending node id (the allocator hands out contiguous
188	    // id blocks in emission order, so node ids increase monotonically).
189	    nodes.sort_by_key(|ni| ni.node_id);
190	    let mut id_to_index: HashMap<usize, usize> = HashMap::new();
191	    let mut port_to_ref: HashMap<usize, (usize, PortRole)> = HashMap::new();
192	    for (idx, ni) in nodes.iter().enumerate() {
193	        id_to_index.insert(ni.node_id, idx);
194	        for (i, p) in ni.prem_ports.iter().enumerate() {
195	            port_to_ref.insert(*p, (idx, PortRole::Prem(i)));
196	        }
197	        if let Some(ip) = ni.info_port {
198	            port_to_ref.insert(ip, (idx, PortRole::Info));
199	        }
200	        for (i, p) in ni.concl_ports.iter().enumerate() {
201	            port_to_ref.insert(*p, (idx, PortRole::Concl(i)));
202	        }
203	    }
204	
205	    // Placeholder nodes reproducing only the id/port footprint (cell text is
206	    // irrelevant to the edge section, which is all this test compares).
207	    let sys_nodes: Vec<GraphNode> = nodes
208	        .iter()
209	        .map(|ni| match ni.foot {
210	            Foot::Record { nprem, nconcl } => GraphNode::RawRule(
211	                RawRule::new("#t : r", "#000000")
212	                    .premises(vec!["p".to_string(); nprem])
213	                    .conclusions(vec!["c".to_string(); nconcl]),
214	            ),
215	            Foot::Single => GraphNode::Temporal { var: "x".into() },
216	        })
217	        .collect();
218	
219	    let map_end = |ep: &EndPoint| -> EndRef {
220	        match &ep.port {
221	            None => EndRef::Whole(id_to_index[&nid(&ep.node)]),
222	            Some(p) => {
223	                let (idx, role) = port_to_ref[&nid(p)];
224	                match role {
225	                    PortRole::Prem(i) => EndRef::Premise(idx, i),
226	                    PortRole::Info => EndRef::Info(idx),
227	                    PortRole::Concl(i) => EndRef::Conclusion(idx, i),
228	                }
229	            }
230	        }
231	    };
232	
233	    let mut used_info = false;
234	    let mut styles = BTreeSet::new();
235	    let sys_edges: Vec<SysEdge> = edges
236	        .iter()
237	        .map(|e| {
238	            let src = map_end(&e.src);
239	            let dst = map_end(&e.dst);
240	            if matches!(src, EndRef::Info(_)) || matches!(dst, EndRef::Info(_)) {
241	                used_info = true;
242	            }
243	            let attrs: Vec<String> =
244	                e.attrs.iter().map(|(k, v)| format!("{k}=\"{v}\"")).collect();
245	            styles.insert(format!("[{}]", attrs.join(",")));
246	            SysEdge::new(src, dst, map_style(&e.attrs))
247	        })
248	        .collect();
249	
250	    let sys = System { nodes: sys_nodes, edges: sys_edges, ..System::default() };
251	    let out = to_dot(&generate(&sys));
252	
253	    let got: Vec<String> =
254	        out.lines().filter(|l| l.contains(" -> ")).map(|s| s.to_string()).collect();
255	    let want: Vec<String> =
256	        dot.lines().filter(|l| l.contains(" -> ")).map(|s| s.to_string()).collect();
257	    Rebuilt { got, want, used_info, styles }
258	}
