260	/// Load the committed round-13 regeneration fixtures (`tests/fixtures/regen/`).
261	fn regen_fixtures() -> Vec<(String, String)> {
262	    let dir = format!("{}/tests/fixtures/regen", env!("CARGO_MANIFEST_DIR"));
263	    let mut entries: Vec<_> = std::fs::read_dir(&dir)
264	        .unwrap_or_else(|e| panic!("read regen fixtures {dir}: {e}"))
265	        .map(|e| e.unwrap().path())
266	        .filter(|p| p.extension().and_then(|e| e.to_str()) == Some("dot"))
267	        .collect();
268	    entries.sort();
269	    entries
270	        .into_iter()
271	        .map(|p| {
272	            let name = p.file_name().unwrap().to_string_lossy().into_owned();
273	            (name, std::fs::read_to_string(&p).unwrap())
274	        })
275	        .collect()
276	}
