278	/// Rebuild the edge section of every committed capture from structured form and
279	/// assert a byte-exact match, and that the set collectively exercises the record
280	/// info-port anchor and all three round-13 styles.
281	#[test]
282	fn regenerate_edge_sections_byte_exact() {
283	    let fixtures = regen_fixtures();
284	    assert!(fixtures.len() >= 20, "need >= 20 diverse captures, have {}", fixtures.len());
285	
286	    let mut any_info = false;
287	    let mut styles: BTreeSet<String> = BTreeSet::new();
288	    for (name, dot) in &fixtures {
289	        let r = rebuild(dot);
290	        assert_eq!(r.got, r.want, "edge section mismatch regenerating {name}");
291	        any_info |= r.used_info;
292	        styles.extend(r.styles);
293	    }
294	
295	    assert!(any_info, "no capture exercised the info-port anchor (EndRef::Info)");
296	    for bracket in [
297	        "[color=\"purple\",style=\"dashed\"]",
298	        "[style=\"dotted\",color=\"green\"]",
299	        "[color=\"darkorange3\",style=\"dashed\"]",
300	    ] {
301	        assert!(styles.contains(bracket), "regeneration set never exercised style {bracket}");
302	    }
303	}
