305	/// Bulk generalization (off by default). Set `GRAPHCLEAN_CORPUS` to a directory
306	/// of captured `*.dot` payloads; every one's edge section must regenerate
307	/// byte-exact from structured form.
308	#[test]
309	fn regenerate_corpus_dir() {
310	    let Ok(dir) = std::env::var("GRAPHCLEAN_CORPUS") else {
311	        return;
312	    };
313	    let (mut total, mut ok) = (0usize, 0usize);
314	    let mut fails: Vec<String> = Vec::new();
315	    for entry in std::fs::read_dir(&dir).unwrap() {
316	        let path = entry.unwrap().path();
317	        if path.extension().and_then(|e| e.to_str()) != Some("dot") {
318	            continue;
319	        }
320	        let dot = std::fs::read_to_string(&path).unwrap();
321	        total += 1;
322	        let name = path.file_name().unwrap().to_string_lossy().into_owned();
323	        let res = std::panic::catch_unwind(|| {
324	            let r = rebuild(&dot);
325	            r.got == r.want
326	        });
327	        match res {
328	            Ok(true) => ok += 1,
329	            _ if fails.len() < 20 => fails.push(name),
330	            _ => {}
331	        }
332	    }
333	    eprintln!("edge-section regeneration: {ok}/{total} byte-exact");
334	    for f in &fails {
335	        eprintln!("  MISMATCH: {f}");
336	    }
337	    assert_eq!(ok, total, "{} of {} payloads failed edge regeneration", total - ok, total);
338	}
