358	        r.got.iter().any(|l| l == "n131:n128 -> n4[color=\"blue3\",style=\"dashed\"];"),
359	        "info-port anchored edge must regenerate exactly"
360	    );
361	    assert!(r.used_info, "the info-port witness must use EndRef::Info");
362	}
